class Solution:
    def convertDateToBinary(self, date):
        # Independent implementation using manual binary conversion instead of
        # a built-in bin()/toString(2) call.
        def to_binary(n):
            if n == 0:
                return '0'
            bits = []
            while n > 0:
                bits.append(str(n % 2))
                n //= 2
            return ''.join(reversed(bits))

        y, m, d = date.split('-')
        return f"{to_binary(int(y))}-{to_binary(int(m))}-{to_binary(int(d))}"

